// Merge LLM summary with enriched incident data
const incident = $('Enrich Payload').first().json;
const llmOutput = $input.first().json;
const summary = llmOutput.content || llmOutput.text || llmOutput.message?.content || 'LLM summary unavailable — review manually.';

return [{
  json: {
    ...incident,
    llm_summary: summary,
    audit_trail: `[${incident.logged_at}] FraudShield detected ${incident.tier} threat. Score: ${incident.risk_score}/100. LLM Summary: ${summary}`
  }
}];

// Build HIGH tier Slack-style notification
const d = $input.first().json;
const indicators = (d.top_indicators || []).slice(0, 3).join(' | ');

return [{
  json: {
    ...d,
    slack_message: `*HIGH Risk Email Detected*\n*Score:* ${d.risk_score}/100  *Tier:* ${d.tier}\n*Verdict:* ${d.verdict}  *Action:* ${d.outlook_action}\n*AI Summary:* ${d.llm_summary}\n*Top Indicators:* ${indicators}\n*Incident ID:* ${d.incident_id}`,
    notification_type: 'HIGH'
  }
}];

// QUARANTINE CONFIRMED — send feedback to FraudShield PostgreSQL
const incident = $('Merge LLM + Incident').first().json;
const query    = $input.first().json.query;
const now      = new Date().toISOString();

return [{
  json: {
    ...incident,
    action_taken:            'QUARANTINE_CONFIRMED',
    analyst_decision:        'QUARANTINE',
    analyst_decision_at:     now,
    feedback_for_model:      'PHISHING',
    audit_trail:             incident.audit_trail + ` [${now}] Human analyst APPROVED quarantine.`,
    feedback_payload: {
      prediction_id: incident.prediction_id,
      user_verdict:  'PHISHING',
      model_verdict: incident.verdict,
      model_score:   incident.risk_score,
      notes:         `n8n workflow: analyst confirmed QUARANTINE for incident ${incident.incident_id}`
    }
  }
}];

// FALSE POSITIVE — send correction to FraudShield retraining queue
const incident = $('Merge LLM + Incident').first().json;
const now      = new Date().toISOString();

return [{
  json: {
    ...incident,
    action_taken:        'FALSE_POSITIVE',
    analyst_decision:    'SAFE',
    analyst_decision_at: now,
    feedback_for_model:  'LEGITIMATE',
    audit_trail:         incident.audit_trail + ` [${now}] Human analyst REJECTED — false positive. Queued for retraining.`,
    feedback_payload: {
      prediction_id: incident.prediction_id,
      user_verdict:  'LEGITIMATE',
      model_verdict: incident.verdict,
      model_score:   incident.risk_score,
      notes:         `n8n workflow: analyst marked FALSE POSITIVE for incident ${incident.incident_id}`
    }
  }
}];

// Final audit entry — log everything to console and build summary
const d = $input.first().json;
const now = new Date().toISOString();

console.log('=== FraudShield Audit ===');
console.log(JSON.stringify({
  incident_id:      d.incident_id,
  tier:             d.tier,
  risk_score:       d.risk_score,
  action_taken:     d.action_taken,
  analyst_decision: d.analyst_decision,
  logged_at:        d.logged_at,
  decided_at:       d.analyst_decision_at,
  llm_summary:      d.llm_summary,
  audit_trail:      d.audit_trail
}, null, 2));

return [{ json: { ...d, final_audit_at: now, workflow_complete: true } }];

